const runtimeSource = Buffer.from("", 'base64').toString('utf8');
const __runtimeBindings = {
  $: (typeof $ !== 'undefined') ? $ : undefined,
  $json: (typeof $json !== 'undefined') ? $json : undefined,
  $input: (typeof $input !== 'undefined') ? $input : undefined,
  Buffer,
};
const rawResult = (() => {
  const $ = __runtimeBindings.$;
  const $json = __runtimeBindings.$json;
  const $input = __runtimeBindings.$input;
  const Buffer = __runtimeBindings.Buffer;
  return eval('(function(){\n' + runtimeSource + '\n})()');
})();
const first = Array.isArray(rawResult) ? rawResult[0] : rawResult;
const normalized = first && typeof first === 'object' && Object.prototype.hasOwnProperty.call(first, 'json')
  ? first.json
  : first;

if (!normalized || typeof normalized !== 'object' || Array.isArray(normalized)) {
  throw new Error('Wrapped customer code node must resolve to a json object');
}

return [{ json: normalized }];

const raw = $json.confirmation_message
  || $json.body_text
  || $json.tool_input?.message
  || $json.text_to_send;

const chatId = $json.chat_id
  || $json.tool_input?.chat_id
  || $('Edit Fields').first().json.chat_id;

let toolName = $json.tool_name || '';
if (!toolName) {
  try { toolName = $('Split In Batches').item.json.tool_name || ''; } catch (error) {}
}
if (!toolName) {
  try { toolName = $('Format Bypass Call').first().json.tool_name || ''; } catch (error) {}
}

return [{
  json: {
    text_to_send: raw,
    chat_id_to_use: chatId,
    bypass_path: $json.bypass_path || false,
    message_type: $json.message_type || 'text',
    buttons: Array.isArray($json.buttons) ? $json.buttons : [],
    list_sections: (() => { const sr = $json.list_sections; if (Array.isArray(sr)) return sr; if (typeof sr === 'string' && sr) try { return JSON.parse(sr); } catch(e) {} return []; })(),
    customer_ui_state: $json.customer_ui_state || '',
    current_state_fresh: $json.current_state_fresh || $json.db_state || '',
    tool_name: toolName,
  },
}];

