=SELECT message_id AS prev_msg_id FROM public.processed_messages
WHERE message_id = '{{ $json.message_id }}'
LIMIT 1;

=INSERT INTO public.processed_messages (message_id, chat_id)
VALUES ('{{ $('Edit Fields').first().json.message_id }}', {{ $('Edit Fields').first().json.chat_id }})
ON CONFLICT (message_id) DO NOTHING;
SELECT 'marked' AS status;

