const dbRow = $input.first().json;
const editData = $('Edit Fields').first().json;
const state = dbRow.current_state || 'STATE_A';
const cartCount = Number(dbRow.cart_item_count || 0);
const cartTotal = parseFloat(dbRow.cart_total || 0).toFixed(2);
const fp = dbRow.feedback_pending;
const feedbackPending = fp === true || fp === 't' || fp === 'true' || fp === 1 || fp === '1';
const userLanguage = String(dbRow.user_language || 'en');
const browseContext = String(dbRow.browse_context || '');

// Fix 7: suppress cart hint on greeting if cart is stale (>6h old)
const greetingRe = /^(hi|hello|hey|helo|hii|good morning|good evening|good afternoon|namaste|namaskar|start|menu|kem cho|vanakkam)$/i;
const message = String(editData.message || '').trim();
const cartUpdatedAt = dbRow.cart_updated_at;
const cartAgeHours = cartUpdatedAt
  ? (Date.now() - new Date(cartUpdatedAt).getTime()) / 3_600_000
  : 999;

// Always include user_language — AI needs it on EVERY message including greetings
let dbStateHint;
if (greetingRe.test(message) && (state === 'STATE_A' || (state === 'STATE_B' && cartAgeHours > 6))) {
  dbStateHint = '[DB_STATE: STATE_A, cart: empty, user_language: ' + userLanguage + '. CRITICAL: The user has NO active cart right now. Do NOT reference any items from conversation history. Greet fresh.]';
} else {
  dbStateHint = '[DB_STATE: ' + state + ', cart_items: ' + cartCount + ', cart_total: ' + cartTotal + ', user_language: ' + userLanguage + ']';
}

return [{ json: {
  ...editData,
  db_state: dbStateHint,
  last_address: String(dbRow.last_address || ''),
  feedback_pending: feedbackPending,
  feedback_order_id: String(dbRow.feedback_order_id || ''),
  feedback_issue_type: String(dbRow.feedback_issue_type || ''),
  user_language: userLanguage,
  browse_context: browseContext,
} }];

return (function customerRuleRuntime() {
    const input = $json || {};
    const message = String(input.message || '').trim();
    const msg = message.toLowerCase();
    const buttonId = String(input.button_id || '').trim();
    const chatId = String(input.chat_id || '');
    const lastAddress = String(input.last_address || '').trim();
    const feedbackPending = input.feedback_pending === true || input.feedback_pending === 'true' || input.feedback_pending === 't' || input.feedback_pending === 1 || input.feedback_pending === '1';
    const feedbackOrderId = String(input.feedback_order_id || '').trim();
    const feedbackIssueType = String(input.feedback_issue_type || '').trim();
    const browseContext = String(input.browse_context || '').trim();
    const dbStateMatch = /\[DB_STATE:\s*(STATE_\w+)/.exec(String(input.db_state || ''));
    const currentState = dbStateMatch ? dbStateMatch[1] : 'STATE_A';
    const userLanguage = String(input.user_language || 'en');

    const direct = (tool_name, tool_input) => ({ ...input, bypass_llm: true, tool_calls: [{ tool_name, tool_input }] });
    const directMany = (tool_calls) => ({ ...input, bypass_llm: true, tool_calls });
    const browseDirect = (entryPoint, extra = {}) => direct('browse_catalog', {
      chat_id: chatId,
      user_query: message || buttonId || 'browse',
      entry_point: entryPoint || buttonId || 'browse',
      ...extra,
    });
    const addressPrompt = 'Please send the full delivery address in one message. Example: 12 MG Road, Indiranagar, Bengaluru.';

    const normalizeItemText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
    const parseCatalogSegment = (segment) => {
      const text = normalizeItemText(segment);
      if (!text) return null;

      const weightPrefix = text.match(/^(?:add\s+)?(\d+(?:\.\d+)?)\s*(kg|kgs|g|gm|grams?|ml|l|ltr|litre|liter|litres|liters)\s+(.+)$/i);
      if (weightPrefix) {
        return {
          product_name: normalizeItemText(weightPrefix[3]),
          quantity: parseFloat(weightPrefix[1]) || 1,
          quantity_hint: parseFloat(weightPrefix[1]) || 1,
          quantity_hint_position: 'prefix_weight',
          unit_hint: String(weightPrefix[2] || '').toLowerCase(),
        };
      }

      const prefixQty = text.match(/^(?:add\s+)?(\d+(?:\.\d+)?)\s*[x×]?\s+(.+)$/i);
      if (prefixQty) {
        return {
          product_name: normalizeItemText(prefixQty[2]),
          quantity: parseFloat(prefixQty[1]) || 1,
          quantity_hint: parseFloat(prefixQty[1]) || 1,
          quantity_hint_position: 'prefix',
          unit_hint: '',
        };
      }

      const explicitQty = text.match(/^(.+?)\s+(?:qty|quantity|x)\s*(\d+(?:\.\d+)?)$/i);
      if (explicitQty) {
        return {
          product_name: normalizeItemText(explicitQty[1]),
          quantity: parseFloat(explicitQty[2]) || 1,
          quantity_hint: parseFloat(explicitQty[2]) || 1,
          quantity_hint_position: 'suffix_explicit',
          unit_hint: '',
        };
      }

      return {
        product_name: text,
        quantity: 1,
        quantity_hint: null,
        quantity_hint_position: '',
        unit_hint: '',
      };
    };

    const parseSimpleMultiItem = (value) => {
      const text = String(value || '').trim();
      if (!/,|&|\band\b|\bplus\b/i.test(text)) return [];
      const parts = text
        .split(/\s*(?:,|&|\band\b|\bplus\b)\s*/i)
        .map((part) => normalizeItemText(part))
        .filter(Boolean);
      if (parts.length < 2 || parts.length > 10) return [];

      const parsed = [];
      for (const part of parts) {
        const entry = parseCatalogSegment(part);
        if (!entry || !entry.product_name) return [];
        parsed.push({
          tool_name: 'add_items',
          tool_input: {
            chat_id: chatId,
            product_name: entry.product_name,
            quantity: entry.quantity,
            quantity_hint: entry.quantity_hint,
            quantity_hint_position: entry.quantity_hint_position,
            unit_hint: entry.unit_hint,
            raw_message: part,
          },
        });
      }
      return parsed;
    };

    // NLP script detection — detect Indian language from Unicode codepoints
    function detectNlpLanguage(text) {
      const counts = { hi: 0, bn: 0, te: 0, ta: 0, gu: 0, kn: 0, ml: 0, or: 0, pa: 0 };
      for (const ch of text) {
        const cp = ch.codePointAt(0);
        if (cp >= 0x0900 && cp <= 0x097F) counts.hi++;      // Devanagari → Hindi/Marathi
        else if (cp >= 0x0980 && cp <= 0x09FF) counts.bn++; // Bengali
        else if (cp >= 0x0C00 && cp <= 0x0C7F) counts.te++; // Telugu
        else if (cp >= 0x0B80 && cp <= 0x0BFF) counts.ta++; // Tamil
        else if (cp >= 0x0A80 && cp <= 0x0AFF) counts.gu++; // Gujarati
        else if (cp >= 0x0C80 && cp <= 0x0CFF) counts.kn++; // Kannada
        else if (cp >= 0x0D00 && cp <= 0x0D7F) counts.ml++; // Malayalam
        else if (cp >= 0x0B00 && cp <= 0x0B7F) counts.or++; // Odia
        else if (cp >= 0x0A00 && cp <= 0x0A7F) counts.pa++; // Punjabi/Gurmukhi
      }
      const best = Object.entries(counts).sort((a, b) => b[1] - a[1])[0];
      return best && best[1] >= 2 ? best[0] : null;
    }

    let result = null;

    // ── PRIORITY 1: Language controls — ALWAYS check before any context/browse checks ──
    // This must come first so "language" / "change language" never hits browse_context logic
    if (!result && (buttonId === 'language_select' || /^(language|change language|bhasha|bhaasha|lang|भाषा|மொழி|భాష|ভাষা|ਭਾਸ਼ਾ|ભાષા|ಭಾಷೆ|ഭാഷ|ଭାଷା)$/i.test(msg))) {
      result = direct('language_select', { chat_id: chatId });
    }
    if (!result && buttonId.startsWith('set_lang__')) {
      result = direct('language_select', { chat_id: chatId, lang_code: buttonId.replace('set_lang__', '') });
    }

    // ── PRIORITY 2: NLP auto language detection ──
    // If user types in an Indian script and their stored preference is English (default),
    // auto-switch them silently via language_select with auto_switch flag
    if (!result && userLanguage === 'en') {
      const detectedLang = detectNlpLanguage(message);
      if (detectedLang) {
        result = direct('language_select', { chat_id: chatId, auto_switch: detectedLang });
      }
    }

    // ── PRIORITY 3: S5 Browse context ──
    if (!result && browseContext.startsWith('awaiting_qty__')) {
      const sku = browseContext.replace('awaiting_qty__', '');
      const qty = parseFloat(message) || parseFloat(message.replace(/[^0-9.]/g, '')) || 1;
      if (qty > 0 && qty <= 100) {
        result = direct('add_items', { chat_id: chatId, sku_direct: sku, quantity: qty,
          quantity_hint: qty, quantity_hint_position: 'browse_context', product_name: '' });
      }
    }
    if (!result && browseContext === 'awaiting_search') {
      result = direct('browse_catalog', { chat_id: chatId, entry_point: 'browse_search', user_query: message });
    }
    // S5-address: user previously tapped add_address — next free-text is their delivery address
    // Guard: only on free text (no buttonId) so buttons like cancel/cart still work normally
    if (!result && browseContext === 'awaiting_address' && message && !buttonId) {
      result = direct('process_order', { chat_id: chatId, address: message });
    }

    // ── Button ID routing ──
    if (!result) {
      if (buttonId === 'confirm_order') result = direct('confirm_order', { chat_id: chatId });
      else if (buttonId === 'cancel_order') result = direct('cancel_order', { chat_id: chatId });
      else if (buttonId === 'view_cart') result = direct('view_cart', { chat_id: chatId });
      else if (buttonId === 'checkout') result = direct('process_order', { chat_id: chatId, address: lastAddress || '' });
      else if (buttonId === 'track_order') result = direct('track_order', { chat_id: chatId });
      else if (buttonId === 'get_promos') result = direct('get_promotions', { chat_id: chatId, user_query: 'offers' });
      else if (buttonId === 'start_shopping' || buttonId === 'add_more' || buttonId === 'new_order') result = browseDirect(buttonId || 'browse');
      else if (buttonId === 'browse' || buttonId === 'browse_back_home') result = browseDirect('browse_home');
      else if (buttonId === 'browse_search') result = browseDirect('browse_search_prompt');
      else if (buttonId.startsWith('browse_category__')) {
        result = browseDirect('browse_category', { category_key: buttonId.replace('browse_category__', '') });
      } else if (buttonId.startsWith('browse_item__')) {
        result = browseDirect('browse_item', { focus_sku: buttonId.replace('browse_item__', ''), sku: buttonId.replace('browse_item__', '') });
      } else if (buttonId.startsWith('set_qty__')) {
        const [, sku, qty] = buttonId.split('__');
        const parsedQty = parseFloat(qty || '1') || 1;
        result = direct('add_items', {
          chat_id: chatId, sku_direct: sku, quantity: parsedQty,
          quantity_hint: parsedQty, quantity_hint_position: 'browse_picker', product_name: '',
        });
      } else if (buttonId.startsWith('set_qty_custom__')) {
        result = browseDirect('browse_qty_custom', { focus_sku: buttonId.replace('set_qty_custom__', ''), sku: buttonId.replace('set_qty_custom__', '') });
      } else if (buttonId === 'add_address') result = direct('answer_user', { chat_id: chatId, message: addressPrompt });
      else if (buttonId === 'use_last_address') {
        result = lastAddress
          ? direct('process_order', { chat_id: chatId, address: lastAddress })
          : direct('answer_user', { chat_id: chatId, message: addressPrompt });
      } else if (buttonId.startsWith('add_qty__')) {
        const [, sku, qty] = buttonId.split('__');
        const parsedQty = parseFloat(qty || '1') || 1;
        result = direct('add_items', { chat_id: chatId, sku_direct: sku, quantity: parsedQty, quantity_hint: parsedQty, quantity_hint_position: 'button', product_name: '' });
      } else if (buttonId.startsWith('rate_good__')) {
        result = direct('order_feedback', { chat_id: chatId, order_id: buttonId.replace('rate_good__', ''), action: 'feedback_good' });
      } else if (buttonId.startsWith('rate_bad__')) {
        result = direct('order_feedback', { chat_id: chatId, order_id: buttonId.replace('rate_bad__', ''), action: 'feedback_issue_start' });
      } else if (buttonId.startsWith('issue_wrong_items__')) {
        result = direct('order_feedback', { chat_id: chatId, order_id: buttonId.replace('issue_wrong_items__', ''), action: 'feedback_issue_type', issue_type: 'wrong_items' });
      } else if (buttonId.startsWith('issue_quality__')) {
        result = direct('order_feedback', { chat_id: chatId, order_id: buttonId.replace('issue_quality__', ''), action: 'feedback_issue_type', issue_type: 'quality_issue' });
      } else if (buttonId.startsWith('issue_late__')) {
        result = direct('order_feedback', { chat_id: chatId, order_id: buttonId.replace('issue_late__', ''), action: 'feedback_issue_type', issue_type: 'late_delivery' });
      } else if (feedbackPending && message) {
        result = direct('order_feedback', { chat_id: chatId, order_id: feedbackOrderId, issue_type: feedbackIssueType, message, action: 'feedback_issue_text' });
      }
    }

    // Browse pagination patterns
    if (!result && /^browse_more__/i.test(buttonId)) {
      const parts = buttonId.split('__');
      result = browseDirect('browse_category', { category_key: parts[1], page: Number(parts[2]) || 0 });
    }
    if (!result && /^browse_search_more__/i.test(buttonId)) {
      const page = Number(buttonId.replace('browse_search_more__', '')) || 0;
      result = browseDirect('browse_search', { user_query: browseContext.startsWith('last_search__') ? browseContext.replace('last_search__', '') : (input.last_search_query || ''), page });
    }

    if (!result && currentState === 'STATE_C' && /^(confirm|yes|haan|ok|bilkul|kar do|yep|sure|theek hai)$/i.test(message)) result = direct('confirm_order', { chat_id: chatId }); // Only confirm if STATE_C (pending order awaiting confirmation)
    if (!result && (currentState === 'STATE_B' || currentState === 'STATE_C') && /^(cancel|no|nahi|mat|stop)$/i.test(message)) result = direct('cancel_order', { chat_id: chatId }); // Only cancel if STATE_B or STATE_C
    if (!result && /^(cart|my cart|view cart|cart dikhao)$/i.test(message)) result = direct('view_cart', { chat_id: chatId });
    if (!result && /^(track|track order|where is my order|order status|status)$/i.test(message)) result = direct('track_order', { chat_id: chatId });
    if (!result && /^(offers|offer|promo|promos|discount|discounts|deals)$/i.test(message)) result = direct('get_promotions', { chat_id: chatId, user_query: message });
    if (!result && /^(checkout|bill|place order|done)$/i.test(message)) result = direct('process_order', { chat_id: chatId, address: lastAddress || '' });
    if (!result && /^(browse|shop|start shopping|shop items|show items|show products|menu|help)$/i.test(message)) result = browseDirect(message || 'browse');

    const removeMatch = !result ? message.match(/^(?:remove|delete|drop|cancel)\s+(.+)$/i) : null;
    if (!result && removeMatch) {
      result = direct('add_items', { chat_id: chatId, product_name: removeMatch[1].trim(), quantity: 0, quantity_hint: 0, quantity_hint_position: 'remove', mode: 'remove', raw_message: message });
    }

    const multiToolCalls = !result ? parseSimpleMultiItem(message) : [];
    if (!result && multiToolCalls.length >= 2) {
      result = directMany(multiToolCalls);
    }

    if (!result) {
      const spaceMultiRe = /\b\d+(?:\.\d+)?\s+\w+(?:\s+\w+)?\s+\d+(?:\.\d+)?\s+\w+/;
      if (spaceMultiRe.test(message)) {
        result = { ...input, bypass_llm: false };
      }
    }

    const prefixQty = !result ? message.match(/^(?:add\s+)?(\d+(?:\.\d+)?)\s*[x×]?\s+(.+)$/i) : null;
    if (!result && prefixQty) {
      result = direct('add_items', {
        chat_id: chatId,
        product_name: prefixQty[2].trim(),
        quantity: parseFloat(prefixQty[1]) || 1,
        quantity_hint: parseFloat(prefixQty[1]) || 1,
        quantity_hint_position: 'prefix',
        raw_message: message,
      });
    }

    const explicitQty = !result ? message.match(/^(.+?)\s+(?:qty|quantity|x)\s*(\d+(?:\.\d+)?)$/i) : null;
    if (!result && explicitQty) {
      result = direct('add_items', {
        chat_id: chatId,
        product_name: explicitQty[1].trim(),
        quantity: parseFloat(explicitQty[2]) || 1,
        quantity_hint: parseFloat(explicitQty[2]) || 1,
        quantity_hint_position: 'suffix_explicit',
        raw_message: message,
      });
    }

    const hasListSeparator = /,|&|\band\b|\bplus\b/i.test(message);
    const startsWithWeightStyleQty = /^\d+(?:\.\d+)?\s*(?:kg|kgs|g|gm|grams?|ml|l|ltr|litre|liter|litres|liters)\b/i.test(message);
    if (!result && (hasListSeparator || startsWithWeightStyleQty)) {
      result = { ...input, bypass_llm: false };
    }

    const looksLikeCatalogLine = !/[?]/.test(message)
      && /^[a-z0-9][a-z0-9\s.+-]*$/i.test(message)
      && message.split(/\s+/).filter(Boolean).length <= 5
      && !/^(hi|hello|hey|thanks|thank you|menu|help|owner|setup|checkout|place order|confirm|yes|haan|ok|bilkul|yep|sure|cancel|no|nahi|mat|stop)$/i.test(msg);

    if (!result && looksLikeCatalogLine) {
      result = direct('add_items', {
        chat_id: chatId,
        product_name: message,
        quantity: 1,
        quantity_hint: null,
        quantity_hint_position: '',
        raw_message: message,
      });
    }

    if (!result) {
      result = { ...input, bypass_llm: false, customer_text_routed_via_ai: !!message };
    }

    return result;
  })();

const lastAddress = $('Get Conv State').first().json.last_address || null;
return $json.tool_calls.map(tc => {
  const toolInput = tc.tool_input || {};
  const checkoutAddress = (typeof toolInput === 'object' && toolInput.address) ? toolInput.address : null;
  return { json: { ...$json, tool_name: tc.tool_name, tool_input: tc.tool_input, bypass_path: true, checkout_address: checkoutAddress, last_address: lastAddress } };
});

const d = $json;
const to = String(d.chat_id);
const base = { messaging_product: 'whatsapp', to };
const buttons = (Array.isArray(d.buttons) ? d.buttons : []).filter((button) => button && button.id && button.title);
const sectionsRaw = d.list_sections; const sections = Array.isArray(sectionsRaw) ? sectionsRaw : (typeof sectionsRaw === 'string' && sectionsRaw ? (() => { try { return JSON.parse(sectionsRaw); } catch(e) { return []; } })() : []);

if (d.message_type === 'button' && buttons.length > 0) {
  const bodyText = String(d.body_text || '');
  const safeBody = bodyText.length > 1020 ? bodyText.substring(0, 1017) + '...' : bodyText;
  if (buttons.length > 2 || sections.length > 0) {
    return [{ json: {
      ...base,
      type: 'interactive',
      interactive: {
        type: 'list',
        body: { text: safeBody },
        action: {
          button: 'Menu',
          sections: sections.length ? sections : [{
            title: 'Choose an option',
            rows: buttons.map((button) => ({
              id: String(button.id || ''),
              title: String(button.title || '').slice(0, 24),
            })),
          }],
        },
      },
    } }];
  }
  return [{ json: {
    ...base,
    type: 'interactive',
    interactive: {
      type: 'button',
      body: { text: safeBody },
      action: {
        buttons: buttons.map((button) => ({
          type: 'reply',
          reply: { id: String(button.id || ''), title: String(button.title || '').slice(0, 20) },
        })),
      },
    },
  } }];
}

if (d.message_type === 'list') {
  const bodyText = String(d.body_text || '');
  const safeBody = bodyText.length > 1020 ? bodyText.substring(0, 1017) + '...' : bodyText;
  return [{ json: {
    ...base,
    type: 'interactive',
    interactive: {
      type: 'list',
      body: { text: safeBody },
      action: {
        button: 'Menu',
        sections,
      },
    },
  } }];
}

return [{ json: { ...base, type: 'text', text: { body: String(d.body_text || '') } } }];

const toolName = $json.tool_name || '';
const bodyText = String($json.text_to_send || '');
const text = bodyText.toLowerCase();
let explicitButtons = (Array.isArray($json.buttons) ? $json.buttons : []).filter((button) => button && button.id && button.title);
let explicitSections = Array.isArray($json.list_sections) ? $json.list_sections : [];
const makeMenuSections = (buttons) => [{
  title: 'Choose an option',
  rows: buttons.map((button) => ({
    id: String(button.id || ''),
    title: String(button.title || '').slice(0, 24),
  })),
}];

let isFinalAddResponse = true;
try {
  isFinalAddResponse = $('Split In Batches').context.noItemsLeft !== false;
} catch (error) {}

if (toolName === 'add_items' && !isFinalAddResponse && /added to cart/i.test(bodyText)) {
  explicitButtons = [];
  explicitSections = [];
}

if ($json.message_type === 'list' || explicitSections.length > 0) {
  return [{ json: {
    body_text: bodyText,
    chat_id: $json.chat_id_to_use,
    message_type: 'list',
    buttons: explicitButtons,
    list_sections: explicitSections,
    customer_ui_state: $json.customer_ui_state || '',
    bypass_path: $json.bypass_path || false,
    tool_name: toolName,
    current_state_fresh: $json.current_state_fresh || '',
  } }];
}

if (explicitButtons.length > 0) {
