const raw = $('Build Owner Intent Prompt').first().json || {};
const aiText = (() => { try { return $('Claude Owner Intent Extractor').first().json.text || ''; } catch { return ''; } })();
const message = String(raw.message || '').trim();
const lower = message.toLowerCase();

const baseToolInput = {
  chat_id: String(raw.chat_id || ''),
  message,
  button_id: String(raw.button_id || ''),
  source_type: String(raw.source_type || 'text'),
