  media_mime_type: raw.media_mime_type || '',
  media_filename: raw.media_filename || '',
  media_caption: raw.media_caption || '',
  store_id: raw.owner_store_id || raw.store_id || null,
};

function parseAiPayload(text) {
  const rawText = String(text || '').trim();
  if (!rawText) return {};
  const ticks = String.fromCharCode(96) + String.fromCharCode(96) + String.fromCharCode(96);
  const fenced = rawText
    .replace(new RegExp('^' + ticks + 'json', 'i'), '')
    .replace(new RegExp('^' + ticks, 'i'), '')
    .replace(new RegExp(ticks + '$', 'i'), '')
    .trim();
  const start = fenced.indexOf('{');
  const end = fenced.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) return {};
  try { return JSON.parse(fenced.slice(start, end + 1)); } catch { return {}; }
}

const ai = parseAiPayload(aiText);
const validRoutes = new Set(['owner_inventory', 'owner_promo', 'owner_help', 'owner_onboarding']);
const aiRoute = validRoutes.has(String(ai.route || '').trim()) ? String(ai.route || '').trim() : '';
const aiConfidence = Number(ai.confidence);
const normalizedMessage = String(ai.normalized_message || '').trim();
const helpTopic = String(ai.help_topic || '').trim() || 'general';
const aiClarify = String(ai.clarify_message || '').trim();
const normalizeScope = (value, allowed) => {
  const normalized = String(value || '').trim().toLowerCase();
  return allowed.has(normalized) ? normalized : 'unknown';
};
const normalizeNum = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  return Number.isFinite(num) ? num : null;
};
const inventoryRequest = (() => {
  const src = ai.inventory_request && typeof ai.inventory_request === 'object' ? ai.inventory_request : {};
  const intent = new Set(['create_item', 'update_item', 'create_or_update', 'list_items', 'low_stock', 'search_items', 'hide_item', 'show_item', 'unknown']).has(String(src.intent || '').trim())
    ? String(src.intent || '').trim()
    : 'unknown';
  const items = Array.isArray(src.items)
    ? src.items
        .filter((item) => item && typeof item === 'object')
        .map((item) => ({
          item_text: String(item.item_text || item.item_name || item.target_text || '').trim(),
          price: normalizeNum(item.price),
          stock: normalizeNum(item.stock),
          unit: String(item.unit || '').trim(),
          category: String(item.category || '').trim(),
          brand: String(item.brand || '').trim(),
          action_hint: String(item.action_hint || item.intent || '').trim().toLowerCase(),
        }))
        .filter((item) => item.item_text || item.price !== null || item.stock !== null || item.unit || item.category || item.brand)
    : [];
  return {
    intent,
    scope_hint: normalizeScope(src.scope_hint, new Set(['single', 'group', 'unknown'])),
    search_term: String(src.search_term || '').trim(),
    clarification_reason: String(src.clarification_reason || '').trim(),
    items,
  };
})();
const promoRequest = (() => {
  const src = ai.promo_request && typeof ai.promo_request === 'object' ? ai.promo_request : {};
  const intent = new Set(['create_promo', 'list_promos', 'deactivate_promo', 'unknown']).has(String(src.intent || '').trim())
    ? String(src.intent || '').trim()
    : 'unknown';
  const discountType = new Set(['percentage', 'flat', 'unknown']).has(String(src.discount_type || '').trim())
    ? String(src.discount_type || '').trim()
    : 'unknown';
  return {
    intent,
    discount_type: discountType,
    discount_value: normalizeNum(src.discount_value),
    min_cart_value: normalizeNum(src.min_cart_value),
    target_text: String(src.target_text || '').trim(),
    scope_hint: normalizeScope(src.scope_hint, new Set(['single', 'family', 'brand', 'order', 'unknown'])),
    promo_code: String(src.promo_code || '').trim().toUpperCase(),
    clarification_reason: String(src.clarification_reason || '').trim(),
  };
})();
const ownerAiPayload = {
  confidence: Number.isFinite(aiConfidence) ? aiConfidence : null,
  clarify_message: aiClarify,
  inventory_request: inventoryRequest,
  promo_request: promoRequest,
};

const promoHint = /%|\bdiscount\b|\bpromo\b|\bpromos\b|\boffer\b|\boffers\b|\bflat\b|\babove\b/i.test(message);
const inventoryHint = /\bstock\b|\bprice\b|\brate\b|\bqty\b|\bquantity\b|\blist\b|\blow stock\b|\bfind\b|\bsearch\b|\bhide\b|\bshow\b|\bimport\b|\bupload\b|\binventory\b|\bitem\b|\bitems\b|\bproducts\b/i.test(lower);
const onboardingHint = /\bupi\b|\bdelivery area\b|\boperating hours\b|\bhours\b|\bstore name\b/i.test(lower);

let route = aiRoute;
if (!route || !Number.isFinite(aiConfidence) || aiConfidence < 0.65) {
  if (promoHint) route = 'owner_promo';
